package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isPrivateIP checks if an IP address is in a private/internal range
func isPrivateIP(ip net.IP) bool {
	privateRanges := []string{
		"10.0.0.0/8",      // Private network
		"172.16.0.0/12",   // Private network
		"192.168.0.0/16",  // Private network
		"127.0.0.0/8",     // Loopback
		"169.254.0.0/16",  // Link-local (cloud metadata)
		"0.0.0.0/8",       // Current network
		"::1/128",         // IPv6 loopback
		"fc00::/7",        // IPv6 private
		"fe80::/10",       // IPv6 link-local
	}

	for _, cidr := range privateRanges {
		_, network, _ := net.ParseCIDR(cidr)
		if network != nil && network.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDialContext is a dial function that validates IP addresses at connection time
// This prevents DNS rebinding attacks
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// If host is an IP address, validate it directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private IP is not allowed")
		}
	} else {
		// Resolve the hostname to IP addresses
		ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
		if err != nil {
			return nil, err
		}

		// Check if any resolved IP is private
		for _, ipAddr := range ips {
			if isPrivateIP(ipAddr.IP) {
				return nil, fmt.Errorf("connection to private IP is not allowed")
			}
		}
	}

	// Use the default dialer with timeout
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	return dialer.DialContext(ctx, network, addr)
}

// validateHostname checks if the hostname resolves to a non-private IP
func validateHostname(hostname string) error {
	// Block known dangerous hostnames
	lowerHostname := strings.ToLower(hostname)
	blockedHosts := []string{
		"localhost",
		"localhost.localdomain",
		"ip6-localhost",
		"ip6-loopback",
		"metadata.google.internal",
		"metadata",
		"169.254.169.254",
	}
	for _, blocked := range blockedHosts {
		if lowerHostname == blocked || strings.HasSuffix(lowerHostname, "."+blocked) {
			return fmt.Errorf("webhook URL cannot point to internal or metadata endpoints")
		}
	}

	// Check if hostname is an IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to internal/private IP addresses")
		}
		return nil
	}

	// Resolve the hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	// Check if any resolved IP is in a private range
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to internal/private IP addresses")
		}
	}

	return nil
}

// validateWebhookURL performs SSRF protection checks
func validateWebhookURL(webhookURL string) error {
	parsedURL, err := url.ParseRequestURI(webhookURL)
	if err != nil {
		return fmt.Errorf("invalid webhook URL format")
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("webhook URL must use http or https scheme")
	}

	// Get the hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname in webhook URL")
	}

	// Validate hostname
	if err := validateHostname(hostname); err != nil {
		return err
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate webhook URL with SSRF protection
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a custom HTTP client with SSRF protection
	transport := &http.Transport{
		DialContext: safeDialContext,
	}

	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Don't follow redirects
		},
	}

	// Send test request to webhook URL using GET method
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

