package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// privateCIDRs contains CIDR blocks for private/reserved IP ranges
var privateCIDRs = []string{
	"0.0.0.0/8",        // Current network (only valid as source)
	"10.0.0.0/8",       // Private network
	"127.0.0.0/8",      // Loopback
	"169.254.0.0/16",   // Link-local (AWS metadata service)
	"172.16.0.0/12",    // Private network
	"192.0.0.0/24",     // IETF Protocol Assignments
	"192.0.2.0/24",     // TEST-NET-1
	"192.168.0.0/16",   // Private network
	"198.18.0.0/15",    // Network benchmark tests
	"198.51.100.0/24",  // TEST-NET-2
	"203.0.113.0/24",   // TEST-NET-3
	"224.0.0.0/4",      // IP multicast
	"240.0.0.0/4",      // Reserved
	"::1/128",          // IPv6 loopback
	"fc00::/7",         // IPv6 unique local
	"fe80::/10",        // IPv6 link-local
}

// privateIPBlocks contains parsed CIDR blocks
var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range privateCIDRs {
		_, block, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address is private/internal/reserved
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check against private/reserved IP blocks
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}

	return false
}

// safeDial validates resolved IP before connecting to prevent DNS rebinding attacks
func safeDial(ctx context.Context, network, addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Validate all resolved IPs to prevent DNS rebinding
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private or reserved IP addresses is not allowed")
		}
	}

	// Use default dialer for actual connection
	dialer := &net.Dialer{}
	return dialer.DialContext(ctx, network, addr)
}

// validateWebhookURL performs SSRF protection checks on the URL
func validateWebhookURL(webhookURL string) error {
	parsedURL, err := url.ParseRequestURI(webhookURL)
	if err != nil {
		return fmt.Errorf("invalid webhook URL format")
	}

	// Ensure the URL has a valid scheme (only http/https allowed)
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("webhook URL must use http or https scheme")
	}

	// Block URLs with credentials (user:pass@host)
	if parsedURL.User != nil {
		return fmt.Errorf("webhook URL cannot contain credentials")
	}

	// Get the hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid webhook URL: missing hostname")
	}

	// Block localhost hostname variations
	lowerHostname := strings.ToLower(hostname)
	blockedHosts := []string{
		"localhost",
		"localhost.localdomain",
		"ip6-localhost",
		"ip6-loopback",
	}
	for _, blocked := range blockedHosts {
		if lowerHostname == blocked {
			return fmt.Errorf("webhook URL cannot point to localhost")
		}
	}

	// Check if hostname is a direct IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to private or internal IP addresses")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL and perform SSRF protection checks
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a custom HTTP client with timeout and safe dialer for SSRF protection
	transport := &http.Transport{
		DialContext: safeDial,
	}

	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Validate redirect URLs to prevent bypass via redirects
			if err := validateWebhookURL(req.URL.String()); err != nil {
				return err
			}
			// Limit redirect count
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			return nil
		},
	}

	// Send test request to webhook URL using GET method
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

