package main

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookStorage stores webhook configurations
type WebhookStorage struct {
	mu      sync.RWMutex
	configs map[string]WebhookConfig
}

var webhookStorage = &WebhookStorage{
	configs: make(map[string]WebhookConfig),
}

// ConfigureWebhook handles POST requests to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Validate webhook_url field
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Save the configuration
	webhookStorage.mu.Lock()
	webhookStorage.configs["default"] = config
	webhookStorage.mu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":       true,
		"message":       "Webhook configured successfully",
		"webhook_url":   config.WebhookURL,
		"response_code": resp.StatusCode,
	})
}

func main() {
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}

