package main

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigStore stores webhook configurations in memory
type ConfigStore struct {
	mu          sync.RWMutex
	webhookURLs []string
}

// Global store for webhook configurations
var store = &ConfigStore{
	webhookURLs: make([]string, 0),
}

// ConfigureWebhook handles POST requests to configure a webhook URL
// It validates the URL by sending a test GET request, then saves the configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body: " + err.Error(),
		})
	}

	// Validate webhook_url field
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Save the configuration to store
	store.mu.Lock()
	store.webhookURLs = append(store.webhookURLs, config.WebhookURL)
	store.mu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"data": fiber.Map{
			"webhook_url": config.WebhookURL,
			"status_code": resp.StatusCode,
		},
	})
}

func main() {
	app := fiber.New(fiber.Config{
		AppName: "Webhook Configurator v1.0",
	})

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Health check endpoint
	app.Get("/health", func(ctx *fiber.Ctx) error {
		return ctx.JSON(fiber.Map{
			"status": "ok",
		})
	})

	// Get all configured webhooks
	app.Get("/webhooks", func(ctx *fiber.Ctx) error {
		store.mu.RLock()
		urls := make([]string, len(store.webhookURLs))
		copy(urls, store.webhookURLs)
		store.mu.RUnlock()

		return ctx.JSON(fiber.Map{
			"webhooks": urls,
			"count":    len(urls),
		})
	})

	// Start the server
	fmt.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}

