package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isPrivateIP checks if an IP address is private or internal
func isPrivateIP(ip net.IP) bool {
	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for private IP ranges
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local addresses (includes cloud metadata 169.254.169.254)
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for unspecified address (0.0.0.0)
	if ip.IsUnspecified() {
		return true
	}

	return false
}

// validateHostname checks if a hostname resolves to a public IP
func validateHostname(hostname string) error {
	// Check for localhost variations
	lowerHostname := strings.ToLower(hostname)
	if lowerHostname == "localhost" || lowerHostname == "localhost.localdomain" {
		return fmt.Errorf("webhook URL cannot point to localhost")
	}

	// Check if hostname is an IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to private or internal IP addresses")
		}
		return nil
	}

	// Resolve the hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve webhook URL hostname")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to private or internal IP addresses")
		}
	}

	return nil
}

// validateWebhookURL performs SSRF protection checks
func validateWebhookURL(webhookURL string) error {
	parsedURL, err := url.ParseRequestURI(webhookURL)
	if err != nil {
		return fmt.Errorf("invalid webhook URL format")
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("webhook URL must use http or https scheme")
	}

	// Extract hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid webhook URL: missing hostname")
	}

	return validateHostname(hostname)
}

// safeDialContext wraps dialing with IP validation to prevent DNS rebinding attacks
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Handle IPv6 addresses in brackets
	if strings.HasPrefix(host, "[") && strings.HasSuffix(host, "]") {
		host = host[1 : len(host)-1]
	}

	// Resolve hostname
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Filter out private IPs and collect public IPs
	var publicIPs []net.IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			publicIPs = append(publicIPs, ip)
		}
	}

	if len(publicIPs) == 0 {
		return nil, fmt.Errorf("connection to private IP addresses is not allowed")
	}

	// Try connecting to each public IP
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	var lastErr error
	for _, ip := range publicIPs {
		// Format IP address for dialing (IPv6 needs brackets)
		ipAddr := ip.String()
		if ip.To4() == nil {
			// IPv6
			ipAddr = "[" + ipAddr + "]"
		}
		conn, err := dialer.DialContext(ctx, network, net.JoinHostPort(ipAddr, port))
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to connect to any resolved IP: %v", lastErr)
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate webhook URL with SSRF protection
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a custom HTTP client with timeout and SSRF protection
	transport := &http.Transport{
		DialContext: safeDialContext,
	}

	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Validate redirect URL to prevent SSRF via redirects
			if err := validateWebhookURL(req.URL.String()); err != nil {
				return fmt.Errorf("redirect to invalid URL: %v", err)
			}
			return nil
		},
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

