package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the API response
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// savedWebhookURL stores the configured webhook URL (simulated persistence)
var savedWebhookURL string

// ConfigureWebhook handles webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// Validate webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test request to validate the webhook URL using GET method
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration
	savedWebhookURL = config.WebhookURL

	// Return success response
	return ctx.Status(http.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

