package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isPrivateIP checks if an IP address is in a private or reserved range
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Define private/reserved IP ranges
	privateIPBlocks := []string{
		"10.0.0.0/8",         // Private Class A
		"172.16.0.0/12",      // Private Class B
		"192.168.0.0/16",     // Private Class C
		"169.254.0.0/16",     // Link-local (AWS metadata, etc.)
		"127.0.0.0/8",        // Loopback
		"0.0.0.0/8",          // Current network
		"224.0.0.0/4",        // Multicast
		"240.0.0.0/4",        // Reserved
		"255.255.255.255/32", // Broadcast
		"::1/128",            // IPv6 loopback
		"fe80::/10",          // IPv6 link-local
		"fc00::/7",           // IPv6 unique local
		"::/128",             // IPv6 unspecified
	}

	for _, block := range privateIPBlocks {
		_, cidr, err := net.ParseCIDR(block)
		if err != nil {
			continue
		}
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

// validateHostname checks if a hostname is safe (not localhost or internal)
func validateHostname(host string) error {
	lowerHost := strings.ToLower(strings.TrimSpace(host))

	// Block localhost variations
	blockedHosts := []string{
		"localhost",
		"localhost.localdomain",
		"ip6-localhost",
		"ip6-loopback",
	}
	for _, blocked := range blockedHosts {
		if lowerHost == blocked {
			return fmt.Errorf("webhook URL cannot point to localhost")
		}
	}

	// Block hostnames that end with internal suffixes
	internalSuffixes := []string{
		".local",
		".internal",
		".localhost",
		".localdomain",
	}
	for _, suffix := range internalSuffixes {
		if strings.HasSuffix(lowerHost, suffix) {
			return fmt.Errorf("webhook URL cannot point to internal addresses")
		}
	}

	return nil
}

// secureDialContext creates a custom dial function that validates resolved IPs
// This prevents SSRF attacks including DNS rebinding
func secureDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address format")
	}

	// Remove brackets from IPv6 addresses in URL format
	host = strings.TrimPrefix(strings.TrimSuffix(host, "]"), "[")

	var targetIPs []net.IP

	// Check if host is already an IP address
	if ip := net.ParseIP(host); ip != nil {
		// Host is an IP address, validate it directly
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("cannot connect to private or internal IP addresses")
		}
		targetIPs = []net.IP{ip}
	} else {
		// Host is a domain name, validate hostname first
		if err := validateHostname(host); err != nil {
			return nil, err
		}

		// Resolve the hostname
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve hostname")
		}

		// Check all resolved IPs are not private
		for _, resolvedIP := range ips {
			if isPrivateIP(resolvedIP) {
				return nil, fmt.Errorf("cannot connect to private or internal IP addresses")
			}
		}

		targetIPs = ips
	}

	if len(targetIPs) == 0 {
		return nil, fmt.Errorf("no valid IP addresses found")
	}

	// Create dialer with timeout
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	// Connect directly to the validated IP to prevent DNS rebinding
	return dialer.DialContext(ctx, network, net.JoinHostPort(targetIPs[0].String(), port))
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Parse and validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Create a custom HTTP client with security settings
	transport := &http.Transport{
		DialContext: secureDialContext,
	}

	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		// Prevent redirects to potentially malicious addresses
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Don't follow redirects
		},
	}

	// Send test request to webhook URL using GET method
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

