	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// APIResponse represents the standard API response
type APIResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// webhookStore stores webhook configurations (in-memory storage)
var webhookStore = make(map[string]string)

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "Invalid JSON request body",
		})
	}

	// Validate that webhook_url is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Create an HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the webhook configuration
	webhookStore["default"] = config.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(APIResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Create a new Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	app.Listen(":3000")
}

